let groupTemplate;
let itemTemplate;

function renderSearchResults(data) {
  const container = document.querySelector(".lower-part");

  // Cache templates ONLY ONCE
  if (!groupTemplate) {
    groupTemplate = container.querySelector(".group").cloneNode(true);
    itemTemplate = container.querySelector(".item").cloneNode(true);
  }

  container.innerHTML = "";

  function createGroup(title, list, type) {
    if (!list || list.length === 0) return;

    // ✅ ALWAYS CLONE
    const group = groupTemplate.cloneNode(true);

    group.querySelector(".group-name p").textContent = title;

    // remove template items inside group
    group.querySelectorAll("a.item").forEach(el => el.remove());

    list.forEach((item) => {
      // ✅ ALWAYS CLONE
      const node = itemTemplate.cloneNode(true);

      const img = node.querySelector(".item-image");
      const nameEl = node.querySelector(".item-name p");
      const descEl = node.querySelector(".item-desc p");
      const descWrapper = node.querySelector(".item-desc");

      // fallback image
      let fallbackImg = node.querySelector(".no-image");
      if (!fallbackImg) {
        fallbackImg = document.createElement("div");
        fallbackImg.className = "no-image";
        fallbackImg.textContent = "No Image Available";
        fallbackImg.style.cssText = `
          width: 20%;
          height: 80px;
          display: flex;
          align-items: center;
          justify-content: center;
          background: #f0f0f0;
          font-size: 10px;
          color: #666;
          border-radius: 8px;
        `;
        img.parentNode.insertBefore(fallbackImg, img);
      }

      // ---- TYPE HANDLING ----
      if (type === "items") {
        node.href = `/erp/item/${item.name}`;
        nameEl.textContent = item.web_item_name || "Unnamed Item";

        if (item.website_image) {
          img.src = item.website_image;
          img.style.display = "block";
          fallbackImg.style.display = "none";
        } else {
          img.style.display = "none";
          fallbackImg.style.display = "flex";
        }

        descEl.textContent =
          item.short_description || "No description available";
        descWrapper.style.display = "-webkit-box";
      }

      if (type === "categories") {
        node.href = `/erp/category/${item.name}`;
        nameEl.textContent = item.name;

        if (item.category_image) {
          img.src = item.category_image;
          img.style.display = "block";
          fallbackImg.style.display = "none";
        } else {
          img.style.display = "none";
          fallbackImg.style.display = "flex";
        }

        descEl.textContent =
          item.description || "No description available";
        descWrapper.style.display = "-webkit-box";
      }

      if (type === "collections") {
        node.href = `/erp/collection/${item.name}`;
        nameEl.textContent = item.name;

        if (item.collection_image) {
          img.src = item.collection_image;
          img.style.display = "block";
          fallbackImg.style.display = "none";
        } else {
          img.style.display = "none";
          fallbackImg.style.display = "flex";
        }

        descEl.textContent =
          item.description || "No description available";
        descWrapper.style.display = "-webkit-box";
      }

      group.appendChild(node);
    });

    container.appendChild(group);
  }

  createGroup("Items", data.items, "items");
  createGroup("Categories", data.categories, "categories");
  createGroup("Collections", data.collections, "collections");
}

if (!this.dataset.blockId) {
  renderSearchResults({})
}

